import{_ as l,c as e,o as t,V as i}from"./chunks/framework.1sOznGPE.js";const j=JSON.parse('{"title":"Node.js介绍","description":"","frontmatter":{},"headers":[],"relativePath":"guide/node/node介绍.md","filePath":"guide/node/node介绍.md","lastUpdated":null}'),r={name:"guide/node/node介绍.md"},o=i('<h1 id="node-js介绍" tabindex="-1">Node.js介绍 <a class="header-anchor" href="#node-js介绍" aria-label="Permalink to &quot;Node.js介绍&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><ol><li>Node.js 不是一门语言也不是框架，它只是基于 Google V8 引擎的 JavaScript 运行时环境。</li><li>Node.js 是构建在 V8 引擎之上的，V8引擎是由 C/C++ 编写的，因此我们的 JavaScript 代码需要由 C/C++ 转化后再执行。</li><li>Node.js 使用异步 I/O 和事件驱动的设计理念，可以高效地处理大量并发请求，提供了非阻塞式 I/O 接口和事件循环机制，使得开发人员可以编写高性能、可扩展的应用程序，异步I/O最终都是由 <code>libuv</code> 事件循环库去实现的。</li><li>Node.js使用 <a href="https://www.npmjs.com" target="_blank" rel="noreferrer">npm</a> 作为包管理工具类似于 python 的 pip，或者是 Java 的Maven，目前 npm 拥有上百万个模块。</li><li><strong>Node.js适合干一些IO密集型应用</strong>，不适合CPU密集型应用，Node.js IO依靠 libuv 有很强的处理能力，而CPU因为 Node.js 单线程原因，容易造成CPU占用率高，如果非要做CPU密集型应用，可以使用C++插件编写 或者Node.js 提供的<code>cluster</code>。(CPU密集型指的是图像的处理 或者音频处理需要大量数据结构 + 算法)</li></ol><h2 id="应用场景" tabindex="-1">应用场景 <a class="header-anchor" href="#应用场景" aria-label="Permalink to &quot;应用场景&quot;">​</a></h2><ul><li><p>前端</p><ul><li>Vue、React、Angular</li></ul></li><li><p>后端</p><ul><li>serverLess</li><li>web应用：express、koa、Nest.js</li><li>RPC服务：gRPC</li></ul></li><li><p>桌面端</p><ul><li>electron</li></ul></li><li><p>移动端</p><ul><li>hybrid</li><li>React Native</li></ul></li><li><p>前端</p><ul><li>Vue Angular React nuxtjs nextjs</li></ul></li><li><p>后端</p><ul><li>serverLess</li><li>web应用 epxress Nestjs koa</li><li>RPC 服务 gRPC</li><li>爬虫 Puppeteer cheerio</li><li>BFF层 网关层</li><li>及时性应用socket.io</li></ul></li><li><p>桌前端</p><ul><li>electron</li><li>tauri</li><li>NWjs</li></ul></li><li><p>移动端</p><ul><li>weex</li><li>ionic</li><li>hybrid</li><li>React Native</li></ul></li><li><p>基建端</p><ul><li>webpack、vite、rollup、gulp</li><li>less、scss、PostCSS</li><li>babel、swc</li><li>inquire、command、shelljs</li></ul></li><li><p>嵌入式</p><ul><li>Ruff js</li></ul></li><li><p>单元测试</p><ul><li>jest、vitest、e2e</li></ul></li><li><p>CICD</p><ul><li>Jenkins、docker、Husky、miniprogram-ci</li></ul></li><li><p>反向代理</p><ul><li>http-proxy、Any-proxy</li></ul></li></ul><table><thead><tr><th>站点</th><th>地址</th></tr></thead><tbody><tr><td>Node.js官网</td><td><a href="https://nodejs.org" target="_blank" rel="noreferrer">https://nodejs.org</a></td></tr><tr><td>Node.js Github</td><td><a href="https://github.com/nodejs" target="_blank" rel="noreferrer">https://github.com/nodejs</a></td></tr><tr><td>Node.js中文文档</td><td><a href="https://www.nodeapp.cn/" target="_blank" rel="noreferrer">https://www.nodeapp.cn/</a></td></tr><tr><td>npm地址</td><td><a href="https://www.npmjs.com/" target="_blank" rel="noreferrer">https://www.npmjs.com/</a></td></tr><tr><td>npm文档</td><td><a href="https://docs.npmjs.com/" target="_blank" rel="noreferrer">https://docs.npmjs.com/</a></td></tr></tbody></table>',6),a=[o];function s(d,n,p,u,c,h){return t(),e("div",null,a)}const m=l(r,[["render",s]]);export{j as __pageData,m as default};
